import ts from"typescript";import{getPropertyValues}from"../../typescript/ast-helpers.js";const ASTRO_CONFIG_SPECIFIER="astro/config";export const getSrcDir=t=>function t(e){if(ts.isObjectLiteralExpression(e)){const t=getPropertyValues(e,"srcDir");if(t.size>0)return Array.from(t)[0]}let r;return ts.forEachChild(e,e=>{const s=t(e);return!!s&&(r=s,!0)}),r}(t)??"src";export const usesSharpImageService=t=>{for(const e of t.statements){if(!ts.isImportDeclaration(e)||!ts.isStringLiteral(e.moduleSpecifier))continue;if("astro/config"!==e.moduleSpecifier.text)continue;const t=e.importClause?.namedBindings;if(t&&ts.isNamedImports(t))for(const e of t.elements)if("sharpImageService"===(e.propertyName?.text??e.name.text))return!0}return!1};